func TestWaveMonitor_AbortKeyDeletesOrchestrator(t *testing.T) {
	const planFile = "abort-test.md"

	plan := &taskparser.Plan{
		Waves: []taskparser.Wave{
			{Number: 1, Tasks: []taskparser.Task{{Number: 1, Title: "Task 1", Body: "do it"}}},
