}

// navRowKind enumerates the distinct row types rendered in the nav panel.
type navRowKind int

const (
	navRowPlanHeader navRowKind = iota
	navRowInstance
	navRowSoloHeader
	navRowTopicHeader
	navRowImportAction
	navRowDeadToggle
	navRowDeadPlan
	navRowHistoryToggle
	navRowHistoryPlan
